#!/usr/bin/env luajit

package.path = "./?.lua;./?/init.lua;./experiments/lua_interpreter_vm/spongejit/?.lua;" .. package.path

local ffi = require("ffi")
local bit = require("bit")
local Materialize = require("src.materialize_native_x64")
local Constants = require("experiments.lua_interpreter_vm.src.constants")

ffi.cdef[[
typedef unsigned int uint32_t;
typedef unsigned short uint16_t;
typedef int int32_t;
typedef unsigned long long uint64_t;
typedef uint64_t SponFactSig;
typedef uint32_t SponStencilId;

typedef struct SponTValueABI {
  unsigned long long value_;
  unsigned char tt_;
} SponTValueABI;
typedef struct SponExecCtx {
  void *stack;
  SponTValueABI *k;
  SponTValueABI scratch[256];
  uint32_t exit_kind;
  uint32_t exit_pc;
  uint32_t exit_op_idx;
  uint32_t exit_hole;
} SponExecCtx;

typedef struct {
  SponStencilId stencil_id;
  uint32_t pc_start;
  uint32_t pc_end;
} SponStencilChoice;

typedef struct {
  uint64_t pattern_probes;
  uint64_t candidate_checks;
  uint32_t choices;
  uint32_t status;
  uint32_t covered_end;
  uint32_t first_uncovered_pc;
  uint32_t no_candidate_opcode;
} SponSelectStats;

typedef struct {
  uint32_t code_offset;
  uint16_t reloc_kind;
  uint16_t role_kind;
  uint16_t op_idx;
  int32_t role_arg;
  int32_t addend;
} SponDataReloc;

typedef struct {
  uint32_t code_offset;
  uint16_t reloc_kind;
  uint16_t edge_kind;
  uint16_t endpoint_index;
  int32_t target_delta;
} SponControlReloc;

typedef struct {
  uint16_t op_idx;
  uint8_t logical_slot;
  uint8_t field_kind;
} SponSlotMapEntry;

typedef struct {
  SponStencilId stencil_id;
  uint32_t offset;
  uint32_t size;
  uint32_t endpoint_start;
  uint32_t data_reloc_start;
  uint32_t control_reloc_start;
  uint32_t slotmap_start;
  uint32_t projection_start;
  uint32_t dependency_start;
  uint16_t len;
  uint16_t n_endpoints;
  uint16_t n_data_relocs;
  uint16_t n_control_relocs;
  uint16_t n_slotmaps;
  uint16_t n_projections;
  uint16_t n_dependencies;
  uint16_t flags;
  uint16_t physical_abi;
  uint16_t reserved;
  uint64_t pattern_key;
  SponFactSig selector_sig;
  SponFactSig required_sig;
  SponFactSig checked_sig;
  SponFactSig produced_sig;
  SponFactSig killed_sig;
} SponStencilDesc;

uint32_t spon_bank_stencil_count(void);
uint32_t spon_bank_pattern_count(void);
const SponStencilDesc *spon_get_stencil(SponStencilId id);
const unsigned char *spon_stencil_data(SponStencilId id);
const SponDataReloc *spon_stencil_data_relocs(SponStencilId id, uint32_t *out_n);
const SponControlReloc *spon_stencil_control_relocs(SponStencilId id, uint32_t *out_n);
const SponStencilChoice *spon_select_flow_flags_slots_stats(const uint32_t *bc, uint32_t start, uint32_t end,
                                                           SponFactSig entry_sig, SponFactSig observed_sig,
                                                           uint16_t required_stencil_flags,
                                                           const SponSlotMapEntry *actual_slots,
                                                           uint32_t n_actual_slots,
                                                           uint32_t *out_n,
                                                           SponSelectStats *stats);
]]

local function assert_eq(a, b, msg) if a ~= b then error((msg or "assert_eq failed") .. ": " .. tostring(a) .. " ~= " .. tostring(b), 2) end end
local function assert_true(x, msg) if not x then error(msg or "assert_true failed", 2) end end

local bank_path = "experiments/lua_interpreter_vm/spongejit/build/sponbank/libsponbank.so"
do
  local f = io.open(bank_path, "rb")
  assert_true(f ~= nil, "missing generated L1 bank: run cd experiments/lua_interpreter_vm/spongejit && make stencils && make bank")
  if f then f:close() end
end

local bank = ffi.load(bank_path)
assert_true(bank.spon_bank_stencil_count() > 0, "empty stencil bank")
assert_true(bank.spon_bank_pattern_count() > 0, "empty pattern bank")

local function bytes_to_hex(p, n)
  local out = {}
  for i = 0, n - 1 do out[#out + 1] = string.format("%02x", tonumber(p[i])) end
  return table.concat(out)
end

local function c_data_relocs(id)
  local n = ffi.new("uint32_t[1]")
  local p = bank.spon_stencil_data_relocs(id, n)
  local out = {}
  for i = 0, tonumber(n[0]) - 1 do
    out[#out + 1] = {
      code_offset = tonumber(p[i].code_offset),
      reloc_kind = tonumber(p[i].reloc_kind),
      role_kind = tonumber(p[i].role_kind),
      op_idx = tonumber(p[i].op_idx),
      role_arg = tonumber(p[i].role_arg),
      addend = tonumber(p[i].addend),
    }
  end
  return out
end

local function c_control_relocs(id)
  local n = ffi.new("uint32_t[1]")
  local p = bank.spon_stencil_control_relocs(id, n)
  local out = {}
  for i = 0, tonumber(n[0]) - 1 do
    out[#out + 1] = {
      code_offset = tonumber(p[i].code_offset),
      reloc_kind = tonumber(p[i].reloc_kind),
      edge_kind = tonumber(p[i].edge_kind),
      endpoint_index = tonumber(p[i].endpoint_index),
      target_delta = tonumber(p[i].target_delta),
    }
  end
  return out
end

local function from_bank(id)
  local d = bank.spon_get_stencil(id)
  assert_true(d ~= nil, "missing stencil descriptor " .. tostring(id))
  assert_true(bit.band(tonumber(d.flags), 10) == 10, "selected stencil is not exact native: " .. tostring(id))
  assert_true(tonumber(d.size) > 0, "selected stencil has no native bytes: " .. tostring(id))
  local data = bank.spon_stencil_data(id)
  assert_true(data ~= nil, "spon_stencil_data returned NULL: " .. tostring(id))
  return {
    stencil_id = tonumber(d.stencil_id),
    executable = true,
    flags = tonumber(d.flags),
    code_size = tonumber(d.size),
    code_hex = bytes_to_hex(data, tonumber(d.size)),
    data_relocs = c_data_relocs(id),
    control_relocs = c_control_relocs(id),
  }
end

local function has_edge(st, edge_kind)
  for _, cr in ipairs(st.control_relocs or {}) do if cr.edge_kind == edge_kind then return true end end
  return false
end

local FIELD_KIND = { a = 1, b = 2, c = 3, dest = 4, aux = 5 }

local function actual_slot_entries(ops)
  local xs = {}
  for pc, op in ipairs(ops or {}) do
    for field, kind in pairs(FIELD_KIND) do
      if op[field] ~= nil and tonumber(op[field]) then
        xs[#xs + 1] = { op_idx = pc - 1, logical_slot = tonumber(op[field]), field_kind = kind }
      end
    end
  end
  local arr = ffi.new("SponSlotMapEntry[?]", #xs)
  for i, x in ipairs(xs) do
    arr[i - 1].op_idx = x.op_idx
    arr[i - 1].logical_slot = x.logical_slot
    arr[i - 1].field_kind = x.field_kind
  end
  return arr, #xs
end

local function select_entries(ops, entry_sig, observed_sig)
  local bc = ffi.new("uint32_t[?]", #ops)
  for i, op in ipairs(ops) do bc[i - 1] = assert(Constants.Op[op.op], "unknown opcode " .. tostring(op.op)) end
  local slots, nslots = actual_slot_entries(ops)
  local out_n = ffi.new("uint32_t[1]")
  local stats = ffi.new("SponSelectStats")
  local choices = bank.spon_select_flow_flags_slots_stats(bc, 0, #ops, entry_sig or 0, observed_sig or 0, 10, slots, nslots, out_n, stats)
  local n = tonumber(out_n[0])
  assert_true(n > 0, "selector returned no choices")
  assert_eq(tonumber(stats.status), 0, "selector did not report full exact coverage")
  local entries = {}
  local pc = 0
  for i = 0, n - 1 do
    local ch = choices[i]
    assert_eq(tonumber(ch.pc_start), pc, "non-contiguous selector choice")
    pc = tonumber(ch.pc_end)
    local st = from_bank(tonumber(ch.stencil_id))
    local slice = {}
    for j = tonumber(ch.pc_start) + 1, tonumber(ch.pc_end) do slice[#slice + 1] = ops[j] end
    entries[#entries + 1] = { stencil = st, ops = slice }
  end
  assert_eq(pc, #ops, "selector did not cover full span")
  assert_eq(tonumber(stats.covered_end), #ops, "selector stats covered_end")
  return entries
end

local function run_image(img, setup, check)
  local mem, n = assert(Materialize.alloc_executable(img.bytes))
  local fn = ffi.cast("void (*)(SponExecCtx *)", mem)
  local stack = ffi.new("SponTValueABI[8]")
  local k = ffi.new("SponTValueABI[8]")
  local ctx = ffi.new("SponExecCtx")
  ctx.stack = stack
  ctx.k = k
  setup(ctx, stack, k)
  fn(ctx)
  check(ctx, stack, k)
  Materialize.free_executable(mem, n)
end

-- End-to-end generated bank path:
-- C selector -> SponStencilChoice[] -> C descriptors/bytes/relocs -> Lua CLP
-- materializer -> mmap -> execute linked image.
do
  local ops = {
    { op = "ADDI", a = 0, b = 0, c = 1 },
    { op = "ADDI", a = 0, b = 0, c = 2 },
    { op = "ADDI", a = 0, b = 0, c = 3 },
    { op = "ADDI", a = 0, b = 0, c = 4 },
    { op = "ADDI", a = 0, b = 0, c = 5 },
  }
  local i64_r0 = 1
  local entries = select_entries(ops, i64_r0, i64_r0)
  assert_true(#entries >= 2, "five-op span should require at least two max-arity choices")
  assert_true(has_edge(entries[1].stencil, 1), "first bank stencil missing fallthrough edge")
  assert_true(has_edge(entries[1].stencil, 2), "first bank stencil missing guard edge")
  local img = Materialize.materialize(entries)
  assert_true(img.ok and img.code_size > 0, "bank materialization failed")

  run_image(img,
    function(ctx, stack)
      stack[0].value_ = 0
      stack[0].tt_ = 3 -- LUA_VNUMINT
      ctx.exit_kind = 99
    end,
    function(ctx, stack)
      assert_eq(tonumber(ctx.exit_kind), 0, "bank-linked ADDI exit")
      assert_eq(tonumber(stack[0].value_), 15, "bank-linked ADDI result")
      assert_eq(tonumber(stack[0].tt_), 3, "bank-linked ADDI tag")
    end)

  run_image(img,
    function(ctx, stack)
      stack[0].value_ = 0
      stack[0].tt_ = 0
      ctx.exit_kind = 99
    end,
    function(ctx, stack)
      assert_eq(tonumber(ctx.exit_kind), 1, "bank-linked guard exit")
      assert_eq(tonumber(stack[0].value_), 0, "guard failure must not run linked span")
    end)
end

-- Newly modeled structural/dynamic VM boundary opcodes are selected from the
-- generated bank and materialize to exact boundary exits, not hidden fallbacks.
for _, bop in ipairs({
  { op = "LEN", a = 0, b = 1 },
  { op = "MMBIN", a = 0, b = 0, c = 0 },
  { op = "CLOSE", a = 0 },
  { op = "NEWTABLE", a = 0, b = 0, c = 0 },
  { op = "CLOSURE", a = 0, bx = 0 },
  { op = "VARARGPREP", a = 0 },
  { op = "EXTRAARG", ax = 0 },
}) do
  local entries = select_entries({ bop }, 0, 0)
  assert_eq(#entries, 1, bop.op .. " boundary selection count")
  assert_true(has_edge(entries[1].stencil, 3), bop.op .. " missing boundary edge")
  local img = Materialize.materialize(entries)
  assert_true(img.ok and img.code_size > 0, bop.op .. " boundary materialization failed")
  run_image(img,
    function(ctx) ctx.exit_kind = 99 end,
    function(ctx) assert_eq(tonumber(ctx.exit_kind), 2, bop.op .. " boundary exit") end)
end

-- Missing semantic coverage is explicit; the selector must not synthesize a hidden L0 fallback.
do
  local ops = { { op = "GETUPVAL", a = 0, b = 0 } }
  local bc = ffi.new("uint32_t[1]")
  bc[0] = Constants.Op.GETUPVAL
  local slots, nslots = actual_slot_entries(ops)
  local out_n = ffi.new("uint32_t[1]")
  local stats = ffi.new("SponSelectStats")
  bank.spon_select_flow_flags_slots_stats(bc, 0, 1, 0, 0, 10, slots, nslots, out_n, stats)
  assert_eq(tonumber(out_n[0]), 0, "unsupported opcode must not select fallback")
  assert_eq(tonumber(stats.status), 1, "unsupported opcode should report no candidate")
  assert_eq(tonumber(stats.first_uncovered_pc), 0, "uncovered pc")
end

print("ok - SpongeJIT generated bank selects and materializes native span")

#include "sponjit_l1_interpreter.h"

#include <errno.h>
#include <string.h>
#include <sys/mman.h>
#include <unistd.h>

#ifndef MAP_ANONYMOUS
#define MAP_ANONYMOUS MAP_ANON
#endif

#define SPON_MAX_PROJECT_OPS 4096u
#define SPON_MAX_SLOT_ENTRIES (SPON_MAX_PROJECT_OPS * 5u)
#define SPON_MAX_LOGICAL_SLOTS 256u

static void patch_u8(uint8_t *p, uint8_t v) { p[0] = v; }

static void patch_u32(uint8_t *p, uint32_t v) {
  p[0] = (uint8_t)(v & 0xffu);
  p[1] = (uint8_t)((v >> 8) & 0xffu);
  p[2] = (uint8_t)((v >> 16) & 0xffu);
  p[3] = (uint8_t)((v >> 24) & 0xffu);
}

static void patch_i64(uint8_t *p, int64_t v) {
  uint64_t u = (uint64_t)v;
  for (uint32_t i = 0; i < 8; i++) p[i] = (uint8_t)((u >> (i * 8)) & 0xffu);
}

static void patch_f64_from_i32(uint8_t *p, int64_t v) {
  union { double d; uint64_t u; } cvt;
  cvt.d = (double)v;
  for (uint32_t i = 0; i < 8; i++) p[i] = (uint8_t)((cvt.u >> (i * 8)) & 0xffu);
}

static int add_slot_entry(SponSlotMapEntry *slots, uint32_t *nslots, uint16_t op_idx, uint8_t field_kind, int32_t slot) {
  if (slot < 0 || slot >= 8) return 0;
  if (*nslots >= SPON_MAX_SLOT_ENTRIES) return -1;
  slots[*nslots].op_idx = op_idx;
  slots[*nslots].logical_slot = (uint8_t)slot;
  slots[*nslots].field_kind = field_kind;
  (*nslots)++;
  return 0;
}

static int build_opcode_and_slot_inputs(const SponL1Op *ops, uint32_t start, uint32_t end,
                                        uint32_t *bc, SponSlotMapEntry *slots, uint32_t *out_nslots) {
  uint32_t nslots = 0;
  if (!ops || !bc || !slots || !out_nslots || end < start || end > SPON_MAX_PROJECT_OPS) return -1;
  for (uint32_t pc = start; pc < end; pc++) {
    const SponL1Op *op = &ops[pc];
    bc[pc] = op->opcode;
    if (add_slot_entry(slots, &nslots, (uint16_t)pc, SPON_FIELD_A, op->a) < 0) return -1;
    if (add_slot_entry(slots, &nslots, (uint16_t)pc, SPON_FIELD_B, op->b) < 0) return -1;
    if (add_slot_entry(slots, &nslots, (uint16_t)pc, SPON_FIELD_C, op->c) < 0) return -1;
    /* DEST/AUX are optional aliases in the stencil contract; include them when valid. */
    if (add_slot_entry(slots, &nslots, (uint16_t)pc, SPON_FIELD_DEST, op->a) < 0) return -1;
  }
  *out_nslots = nslots;
  return 0;
}

static int actual_slot_lookup(const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots,
                              uint16_t op_idx, uint8_t field_kind, uint8_t *out_slot) {
  if (!actual_slots || !out_slot) return 0;
  for (uint32_t i = 0; i < n_actual_slots; i++) {
    if (actual_slots[i].op_idx == op_idx && actual_slots[i].field_kind == field_kind) {
      *out_slot = actual_slots[i].logical_slot;
      return 1;
    }
  }
  return 0;
}

static void build_logical_slot_map(SponStencilId id, uint32_t pc_start,
                                   const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots,
                                   uint8_t *map, uint8_t *seen) {
  uint32_t n_slotmaps = 0;
  const SponSlotMapEntry *sms = spon_stencil_slotmaps(id, &n_slotmaps);
  memset(map, 0, SPON_MAX_LOGICAL_SLOTS);
  memset(seen, 0, SPON_MAX_LOGICAL_SLOTS);
  if (!sms) return;
  for (uint32_t i = 0; i < n_slotmaps; i++) {
    uint8_t actual = 0;
    uint8_t logical = sms[i].logical_slot;
    uint16_t actual_op_idx = (uint16_t)(pc_start + sms[i].op_idx);
    if (actual_slot_lookup(actual_slots, n_actual_slots, actual_op_idx, sms[i].field_kind, &actual)) {
      map[logical] = actual;
      seen[logical] = 1;
    }
  }
}

static uint8_t remap_slot(uint8_t logical, const uint8_t *map, const uint8_t *seen) {
  return seen[logical] ? map[logical] : logical;
}

static int32_t op_default_imm(const SponL1Op *op) {
  if (!op) return 0;
  switch (op->opcode) {
    case SPON_OP_ADDI:
    case SPON_OP_SHLI:
    case SPON_OP_SHRI:
      return op->c;
    case SPON_OP_LOADI:
    case SPON_OP_LOADF:
      return op->sbx != 0 ? op->sbx : op->bx;
    default:
      if (op->c != 0) return op->c;
      if (op->b != 0) return op->b;
      if (op->sbx != 0) return op->sbx;
      if (op->sj != 0) return op->sj;
      return 0;
  }
}

static int32_t op_const_index(const SponL1Op *op) {
  if (!op) return 0;
  if (op->bx != 0) return op->bx;
  if (op->ax != 0) return op->ax;
  if (op->b != 0) return op->b;
  if (op->c != 0) return op->c;
  return 0;
}

static int32_t op_bool_tag(const SponL1Op *op) {
  if (!op) return SPON_LUA_VTRUE;
  if (op->opcode == SPON_OP_LOADFALSE || op->opcode == SPON_OP_LFALSESKIP) return SPON_LUA_VFALSE;
  return SPON_LUA_VTRUE;
}

static int64_t data_patch_value(const SponL1Op *ops, uint32_t pc_start, const SponDataReloc *r,
                                const uint8_t *map, const uint8_t *seen) {
  const SponL1Op *op = ops ? &ops[pc_start + r->op_idx] : NULL;
  int64_t v = 0;
  switch (r->role_kind) {
    case SPON_DATA_RELOC_SLOT:
    case SPON_DATA_RELOC_SLOT_STORE:
      v = ((int64_t)remap_slot((uint8_t)r->role_arg, map, seen)) * 16;
      break;
    case SPON_DATA_RELOC_IMM:
      v = op_default_imm(op);
      break;
    case SPON_DATA_RELOC_CONST:
      v = ((int64_t)op_const_index(op)) * 16;
      break;
    case SPON_DATA_RELOC_BOOL:
      v = op_bool_tag(op);
      break;
    default:
      return INT64_MIN;
  }
  return v + r->addend;
}

static int patch_data_reloc(uint8_t *code, size_t code_size, size_t base, const SponL1Op *ops,
                            uint32_t pc_start, const SponDataReloc *r,
                            const uint8_t *map, const uint8_t *seen) {
  int64_t v = data_patch_value(ops, pc_start, r, map, seen);
  size_t off = base + r->code_offset;
  if (v == INT64_MIN || off >= code_size) return -1;
  switch (r->reloc_kind) {
    case SPON_RELOC_ABS8:
      if (off + 1 > code_size) return -1;
      patch_u8(code + off, (uint8_t)v);
      return 0;
    case SPON_RELOC_ABS32:
    case SPON_RELOC_ABS32S:
      if (off + 4 > code_size) return -1;
      patch_u32(code + off, (uint32_t)v);
      return 0;
    case SPON_RELOC_ABS64:
      if (off + 8 > code_size) return -1;
      if (r->role_kind == SPON_DATA_RELOC_IMM) {
        const SponL1Op *op = ops ? &ops[pc_start + r->op_idx] : NULL;
        if (op && op->opcode == SPON_OP_LOADF) {
          patch_f64_from_i32(code + off, v);
          return 0;
        }
      }
      patch_i64(code + off, v);
      return 0;
    default:
      return -1;
  }
}

static int patch_pc32(uint8_t *code, size_t code_size, size_t site, int64_t rel) {
  if (site + 4 > code_size) return -1;
  patch_u32(code + site, (uint32_t)(int32_t)rel);
  return 0;
}

static void *alloc_executable(size_t size) {
  if (size == 0) return NULL;
  void *mem = mmap(NULL, size, PROT_READ | PROT_WRITE | PROT_EXEC, MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);
  if (mem == MAP_FAILED) return NULL;
  return mem;
}

void spon_l1_image_init(SponL1Image *img) {
  if (!img) return;
  memset(img, 0, sizeof(*img));
}

void spon_l1_image_free(SponL1Image *img) {
  if (!img) return;
  if (img->code && img->code_size) munmap(img->code, img->code_size);
  spon_l1_image_init(img);
}

int spon_l1_project(const SponL1Op *ops, uint32_t start, uint32_t end,
                    SponFactSig entry_sig, SponFactSig observed_sig,
                    SponL1Image *out_img) {
  uint32_t bc[SPON_MAX_PROJECT_OPS];
  SponSlotMapEntry actual_slots[SPON_MAX_SLOT_ENTRIES];
  uint32_t n_actual_slots = 0;
  uint32_t n_choices = 0;
  SponSelectStats stats;
  size_t total = 0;
  uint32_t pc = start;

  if (!out_img) return -1;
  spon_l1_image_free(out_img);
  memset(&stats, 0, sizeof(stats));

  if (!ops || end <= start || end > SPON_MAX_PROJECT_OPS) return -1;
  if (build_opcode_and_slot_inputs(ops, start, end, bc, actual_slots, &n_actual_slots) != 0) return -1;

  const SponStencilChoice *choices = spon_select_flow_flags_slots_stats(
      bc, start, end, entry_sig, observed_sig, SPON_STENCIL_NATIVE | SPON_STENCIL_EXACT,
      actual_slots, n_actual_slots, &n_choices, &stats);
  if (!choices || n_choices == 0) return -1;

  for (uint32_t i = 0; i < n_choices; i++) {
    const SponStencilDesc *d = spon_get_stencil(choices[i].stencil_id);
    if (!d || (d->flags & (SPON_STENCIL_NATIVE | SPON_STENCIL_EXACT)) != (SPON_STENCIL_NATIVE | SPON_STENCIL_EXACT) || d->size == 0) return -1;
    if (choices[i].pc_start != pc || choices[i].pc_end <= choices[i].pc_start || choices[i].pc_end > end) return -1;
    total += d->size;
    pc = choices[i].pc_end;
  }
  if (pc != end || total == 0) return -1;

  uint8_t *code = (uint8_t *)alloc_executable(total);
  if (!code) return -1;

  size_t bases[4096];
  size_t off = 0;
  for (uint32_t i = 0; i < n_choices; i++) {
    const SponStencilDesc *d = spon_get_stencil(choices[i].stencil_id);
    const unsigned char *src = spon_stencil_data(choices[i].stencil_id);
    if (!src) { munmap(code, total); return -1; }
    bases[i] = off;
    memcpy(code + off, src, d->size);
    off += d->size;
  }

  for (uint32_t i = 0; i < n_choices; i++) {
    uint8_t map[SPON_MAX_LOGICAL_SLOTS];
    uint8_t seen[SPON_MAX_LOGICAL_SLOTS];
    uint32_t n_relocs = 0;
    const SponDataReloc *relocs = spon_stencil_data_relocs(choices[i].stencil_id, &n_relocs);
    build_logical_slot_map(choices[i].stencil_id, choices[i].pc_start, actual_slots, n_actual_slots, map, seen);
    for (uint32_t j = 0; j < n_relocs; j++) {
      if (patch_data_reloc(code, total, bases[i], ops, choices[i].pc_start, &relocs[j], map, seen) != 0) {
        munmap(code, total);
        return -1;
      }
    }
  }

  for (uint32_t i = 0; i < n_choices; i++) {
    uint32_t n_relocs = 0;
    const SponControlReloc *relocs = spon_stencil_control_relocs(choices[i].stencil_id, &n_relocs);
    for (uint32_t j = 0; j < n_relocs; j++) {
      const SponControlReloc *r = &relocs[j];
      if (r->edge_kind == SPON_CONTROL_RELOC_FALLTHROUGH && i + 1 < n_choices) {
        size_t site = bases[i] + r->code_offset;
        int64_t rel = (int64_t)bases[i + 1] - (int64_t)(site + 4);
        if (r->reloc_kind != SPON_RELOC_PC32 || patch_pc32(code, total, site, rel) != 0) {
          munmap(code, total);
          return -1;
        }
      }
    }
  }

  out_img->code = code;
  out_img->code_size = total;
  out_img->n_choices = n_choices;
  out_img->select_stats = stats;
  return 0;
}

uint32_t spon_l1_run(const SponL1Image *img, SponExecCtx *ctx) {
  if (!img || !img->code || !ctx) return SPON_EXIT_RUNTIME_ERROR;
  typedef void (*SponL1Fn)(SponExecCtx *ctx);
  ((SponL1Fn)(void *)img->code)(ctx);
  return ctx->exit_kind;
}

uint32_t spon_l1_interpret_once(const SponL1Op *ops, uint32_t start, uint32_t end,
                                SponFactSig entry_sig, SponFactSig observed_sig,
                                SponExecCtx *ctx) {
  SponL1Image img;
  uint32_t exit_kind;
  spon_l1_image_init(&img);
  if (spon_l1_project(ops, start, end, entry_sig, observed_sig, &img) != 0) return SPON_EXIT_RUNTIME_ERROR;
  exit_kind = spon_l1_run(&img, ctx);
  spon_l1_image_free(&img);
  return exit_kind;
}

#ifndef SPONJIT_L1_INTERPRETER_H
#define SPONJIT_L1_INTERPRETER_H

#include <stddef.h>
#include <stdint.h>

#include "sponbank.h"

#ifdef __cplusplus
extern "C" {
#endif

/* Minimal opcode constants used by the prototype materializer. */
enum {
  SPON_OP_MOVE = 0,
  SPON_OP_LOADI = 1,
  SPON_OP_LOADF = 2,
  SPON_OP_LOADK = 3,
  SPON_OP_LOADKX = 4,
  SPON_OP_LOADFALSE = 5,
  SPON_OP_LFALSESKIP = 6,
  SPON_OP_LOADTRUE = 7,
  SPON_OP_LOADNIL = 8,
  SPON_OP_ADDI = 21,
  SPON_OP_SHLI = 32,
  SPON_OP_SHRI = 33
};

enum {
  SPON_LUA_VNIL = 0,
  SPON_LUA_VFALSE = 1,
  SPON_LUA_VNUMINT = 3,
  SPON_LUA_VTRUE = 17,
  SPON_LUA_VNUMFLT = 19
};

#define SPON_FACT_I64_SLOT(slot_) (((SponFactSig)1) << (slot_))

typedef struct SponL1Op {
  uint32_t opcode;
  int32_t a;
  int32_t b;
  int32_t c;
  int32_t bx;
  int32_t ax;
  int32_t sbx;
  int32_t sj;
} SponL1Op;

typedef struct SponL1Image {
  uint8_t *code;
  size_t code_size;
  uint32_t n_choices;
  SponSelectStats select_stats;
} SponL1Image;

void spon_l1_image_init(SponL1Image *img);
void spon_l1_image_free(SponL1Image *img);

/*
 * Select L1 native stencils from the generated bank and copy/link/patch them
 * into one executable image. This is a prototype projection interpreter step:
 * bytecode+facts -> bank choices -> native image. It does not run SSA.
 */
int spon_l1_project(const SponL1Op *ops, uint32_t start, uint32_t end,
                    SponFactSig entry_sig, SponFactSig observed_sig,
                    SponL1Image *out_img);

/* Execute a previously projected image. Returns ctx->exit_kind. */
uint32_t spon_l1_run(const SponL1Image *img, SponExecCtx *ctx);

/* Convenience function: project, run once, then free the image. */
uint32_t spon_l1_interpret_once(const SponL1Op *ops, uint32_t start, uint32_t end,
                                SponFactSig entry_sig, SponFactSig observed_sig,
                                SponExecCtx *ctx);

#ifdef __cplusplus
}
#endif

#endif

